#include <bits/stdc++.h>
using namespace std;

void Insertion_Sort(int arr[], int n) {

    for(int i = 1; i < n; i++) {
        int j = i;

        // Swaps until the element is at its right position
        while(j != 0 && arr[j - 1] > arr[j]) {
            swap(arr[j - 1], arr[j]);
            arr[j--];
        }
    }
}

int main() {
    int n; 
    cin >> n;

    int arr[n];
    for(int i = 0; i < n; i++) {
        cin >> arr[i];
    }

    Insertion_Sort(arr, n);

    for(int i = 0; i < n; i++) {
        cout << arr[i] << " ";
    }
    cout << "\n";

    return 0;
}

